INSERT INTO skill_branches VALUES(1,'Backend Shield','Money, market, commercial delivery','Backend, IoT/Networks','Service survives failures and duplicates','Sells even without hardware');
INSERT INTO skill_branches VALUES(2,'Systems Blade','C, memory, Linux, toolchain','C/Systems, Linux','Gateway as a Linux service','Framework-independent');
INSERT INTO skill_branches VALUES(3,'Hardware Hands','Soldering, measurements, schematics','Electronics, Debug','Prove bugs with measurements','AI cannot touch physics');
INSERT INTO skill_branches VALUES(4,'Firmware Fire','MCU, firmware, RTOS','Firmware, RTOS','FreeRTOS firmware with watchdog','Real world + timing');
INSERT INTO skill_branches VALUES(5,'Board Craft','KiCad, PCB, revisions','PCB','Carrier board v1','Ownership of the product');
INSERT INTO skill_branches VALUES(6,'Test Alchemy','Python HIL, serial, CI','Testing','Firmware test runner','Bridges backend and embedded');
INSERT INTO skill_branches VALUES(7,'Security Wards','Device identity, updates, threat model','Security','Signed update simulation','Protection from product risks');
INSERT INTO roadmap_stages VALUES(0,'Career Shield','','Backend core','A',1,'Backend','Python backend, SQL, Docker, Linux, tests, migrations, logging','FastAPI/Django docs; PostgreSQL docs; Docker docs; Python design patterns; Clean Architecture','Backend telemetry API: devices, events, PostgreSQL, Docker Compose, tests','You can spin up a project with DB, migrations, logs, tests, and Docker without constant copy-paste','Architecture review, edge cases, test cases','Backend remains a revenue source and fast market entry');
INSERT INTO roadmap_stages VALUES(1,'Backend Reliability','','Queues and resilience','A',2,'Backend','Redis/RabbitMQ, Celery/TaskIQ/RQ, retry, idempotency, structured logs, healthchecks, transactions','PostgreSQL docs; Redis docs; Celery/TaskIQ docs; CMU 15-445 selectively','Service survives duplicates, worker crashes, temporary queue/DB unavailability','Tests cover duplicates, worker crashes, temporary queue/DB unavailability','Failure scenarios and bad data','Skills sell even without embedded');
INSERT INTO roadmap_stages VALUES(2,'C as Gateway to Hardware','','C / memory / tooling','A',3,'C/Systems','C, pointers, memory, structs, bitwise, Make/CMake, gdb, sanitizers, ring buffer','Beej''s Guide to C; Modern C; K. N. King C Programming: A Modern Approach optional','C device simulator: binary packets, checksum, encode/decode, send to backend/gateway','You can explain pointers, stack/heap, endianness, bit masks, and debug segfaults','UB explanation, tests, C code review','C is the base for firmware, embedded Linux, and systems');
INSERT INTO roadmap_stages VALUES(3,'Computer Architecture','','Under the code','A',4,'C/Systems','CPU, registers, memory, stack frame, cache, interrupts, I/O, memory-mapped I/O','Berkeley CS61C or MIT 6.004; Nand2Tetris Part I selectively','Disassemble simple C programs; mini-VM or binary parser','You understand how C becomes machine execution','Assembly and memory layout explanation','Protection from framework dependency');
INSERT INTO roadmap_stages VALUES(4,'Linux Systems','','Backend/system bridge','A',5,'Linux','Processes, threads, signals, files, sockets, permissions, systemd, journalctl, serial devices','OSTEP; MIT 6.1810 selectively','Python gateway as a Linux service: systemd, logs, config, restart, graceful shutdown','Gateway runs as a service, logs, recovers, and survives failures','Failure scenarios, systemd/debug checklist','Embedded Linux and backend intersect here');
INSERT INTO roadmap_stages VALUES(5,'Networks and IoT Protocols','','Device/backend link','A',6,'IoT/Networks','TCP/UDP basics, HTTP, WebSocket/SSE, MQTT, reconnect, timeouts, backoff, device identity','Stanford CS144 selectively; MQTT/Mosquitto docs; Beej Network Programming later','Gateway → MQTT broker → backend worker → PostgreSQL → dashboard','System survives network loss, duplicates, and redelivery','Network failure modeling','IoT/backend is the best bridge to embedded');
INSERT INTO roadmap_stages VALUES(6,'Electronics Hands-On','','Physical minimum','A',7,'Electronics','Ohm''s law, power, ground, LED, buttons, pull-up/pull-down, capacitors, sensors, multimeter, soldering','Electronics for beginners; All About Circuits; MIT 6.002 selectively','Breadboard: button, LED, sensor, power; then solder on perfboard','You can measure voltage, find shorts, continuity-test a circuit, and not confuse GND/VCC','Schematic verification checklist','Physical measurements AI cannot do for you');
INSERT INTO roadmap_stages VALUES(7,'First Microcontroller','','Bare-metal firmware','A',8,'Firmware','GPIO, UART, timers, interrupts, PWM, ADC, I2C, SPI, watchdog','Raspberry Pi Pico C SDK or STM32CubeIDE/ST docs; UT Austin Shape The World','Board reads a sensor and sends data over UART to Python gateway','Device streams data stably for hours; you explain the data path','Datasheet and register walkthrough, mandatory hands-on verification','Low-cost firmware entry without abandoning backend');
INSERT INTO roadmap_stages VALUES(8,'Instrumentation and Debug','','Measure, don''t guess','A',9,'Debug','Multimeter, logic analyzer, serial logs, baud rate, I2C scan, SPI decode, test points, fault tree','Instrument docs; Saleae-style tutorials; datasheets','Debug scenarios: wrong baud rate, broken wire, missing GND, I2C address conflict','You can prove root cause with a measurement or log','Hypothesis tree and verification plan','Top anti-AI skill: physical diagnostics');
INSERT INTO roadmap_stages VALUES(9,'Firmware as Product','','Firmware architecture','A',10,'Firmware','State machines, drivers, HAL boundaries, error codes, config, logging, protocol versioning, memory limits','UT Austin/Valvano Embedded Systems; datasheets; vendor docs','Firmware v1: driver layer, protocol layer, app layer, UART CLI, error counters','Code has layers, protocol, and diagnostics—not one 800-line main.c','Structure and failure mode review','Makes the project an engineering product');
INSERT INTO roadmap_stages VALUES(10,'FreeRTOS','','Real-time thinking','B',11,'RTOS','Tasks, queues, semaphores, mutex, timers, priorities, ISR-to-task, watchdog, stack/heap','FreeRTOS Kernel Book/docs','Sensor task, comm task, health/watchdog task, queue, error stats','You understand priority inversion, ISR limits, stack overflow, watchdog recovery','RTOS tasks and mock interview','RTOS is an important layer for real embedded');
INSERT INTO roadmap_stages VALUES(11,'C++ for Embedded/Linux','','Expand the market','B',12,'C/Systems','RAII, classes, value/reference, move basics, templates minimally, STL cautiously, no-exceptions/no-rtti awareness','LearnCpp; C++ Core Guidelines selectively; vendor examples','C++ firmware/tool module without magic or C++ Linux utility','You know where C++ helps and where it is dangerous','C/C++ solution comparison','C++ appears often in embedded/Linux roles');
INSERT INTO roadmap_stages VALUES(12,'PCB v0: Carrier Board','','First board without heroics','B',13,'PCB','KiCad, schematic, footprints, ERC/DRC, BOM, connectors, test points, decoupling, silkscreen','KiCad docs; datasheets; manufacturer design rules','Carrier board: dev module, sensor, button, LED, connectors, test points','Board passes ERC/DRC, ordered, soldered, continuity-tested, and works','DRC/ERC/BOM checklist','Carrier board lowers the cost of mistakes');
INSERT INTO roadmap_stages VALUES(13,'PCB v1: Revision Discipline','','Engineering cycle','B',14,'PCB','v0 mistakes, ECO, revisions, BOM, component alternates, DFM/DFT, assembly notes','KiCad docs; datasheets; manufacturing rules','Revision v1: fixes, test points, labels, documentation','You explain every v1 change and why v0 was wrong','Changelog and risk list','Revisions matter more than a perfect board on the first try');
INSERT INTO roadmap_stages VALUES(14,'Embedded Linux','','Bridge to industry','B',15,'Linux','Cross-compilation, Buildroot basics, systemd, device files, GPIO/serial, kernel/user boundary','Bootlin Embedded Linux materials; OSTEP; MIT 6.1810 selectively','Linux gateway on SBC: serial/MQTT/logs/local buffering; later Buildroot image','You can build a gateway, run the service, and diagnose it','Configs and logs','Embedded Linux is closer to backend than pure firmware');
INSERT INTO roadmap_stages VALUES(15,'Zephyr / Modern Embedded','','Production-style RTOS','C',16,'RTOS','West, CMake, Kconfig, Devicetree, board configs, drivers, samples','Zephyr docs','Port sensor/logging app to Zephyr','You understand Kconfig/Devicetree/source and Zephyr project structure','Docs navigation','Zephyr is useful but not the first RTOS');
INSERT INTO roadmap_stages VALUES(16,'Hardware Test Automation','','Strong bridge from Python','B',17,'Testing','pytest, serial, flashing scripts, log parsing, reports, HIL basics, CI','pytest docs; pyserial docs; vendor flashing tools','Python test runner: flashes/reboots device, reads UART, verifies commands','Tests catch real firmware/protocol bugs','Test case generation and fault injection','Market bridge: Python + embedded team');
INSERT INTO roadmap_stages VALUES(17,'Security and CPS Thinking','','System maturity','C',18,'Security','Device auth, secrets, TLS, firmware versioning, signing concept, rollback, fault modes, real-time constraints','OWASP IoT checklist; Berkeley EECS149 + Lee/Seshia; vendor security docs','Versioning + signed update simulation + fault injection scenarios','You can explain how the system breaks, is diagnosed, updated, and recovered','Threat modeling assistant','Security/CPS survives technology churn');
INSERT INTO roadmap_stages VALUES(100,'The Hero''s Hall','','Learn the HUD','A',0,'Tutorial','Hero screen, XP bar, ranks, campaign acts, quest focus','This app — HERO / WORLD / QUESTS / TALENTS tabs','Read the Hero screen and understand how your character levels up','You can explain level, rank, XP, campaign progress, and where to find your next quest','Walk through each Hero slide','Onboarding before real learning paths');
INSERT INTO roadmap_stages VALUES(101,'The Quest Board','','Learn quest flow','A',0,'Tutorial','Quest chains, statuses, boss fights, world map, talents','This app — Quest Log and World Map','Complete a full quest chain including a boss fight','You cleared every tutorial quest and know how to mark lessons done','Use Begin Quest and Mark Cleared buttons','Graduate to Systems Engineer Saga');
